7.5 Análise de coesão partidária
Uma das análises mais clássicas em ciência política. Use extrair_votacoes_nominais_por_ano(), que já contém o voto de todos os senadores:
library(ggplot2)

# 1. Votações nominais abertas (excluir votações secretas)
nominais &lt;- extrair_votacoes_nominais_por_ano(anos = 2023) |&gt;
  filter(Secreta == "N",
         Votos.Voto %in% c("Sim", "Não", "Abstenção"))

# 2. Calcular coesão por partido e votação
coesao &lt;- nominais |&gt;
  group_by(Votos.SiglaPartido, CodigoSessaoVotacao) |&gt;
  mutate(
    voto_majoritario = names(sort(table(Votos.Voto), decreasing = TRUE))[1]
  ) |&gt;
  summarise(
    coesao    = mean(Votos.Voto == voto_majoritario),
    n_membros = n(),
    .groups   = "drop"
  ) |&gt;
  filter(n_membros &gt;= 3) |&gt;
  group_by(Votos.SiglaPartido) |&gt;
  summarise(coesao_media = mean(coesao), .groups = "drop") |&gt;
  arrange(desc(coesao_media))

# 3. Visualizar
ggplot(coesao, aes(x = reorder(Votos.SiglaPartido, coesao_media),
                   y = coesao_media)) +
  geom_col(fill = "#e76f51") +
  coord_flip() +
  scale_y_continuous(labels = scales::percent) +
  labs(
    title = "Coesão partidária nas votações nominais abertas (2023)",
    x = NULL, y = "Coesão média"
  ) +
  theme_minimal()

7.6 Análise de similaridade de votação
Quais senadores votam de forma mais parecida? Use a matriz de votos para calcular concordância entre pares:
library(tidyr)

# 1. Filtrar votações abertas com voto explícito
nominais_limpos &lt;- extrair_votacoes_nominais_por_ano(anos = 2023) |&gt;
  filter(Secreta == "N",
         Votos.Voto %in% c("Sim", "Não")) |&gt;
  mutate(voto_num = ifelse(Votos.Voto == "Sim", 1, 0))

# 2. Criar matriz senador × votação
matriz_votos &lt;- nominais_limpos |&gt;
  select(Votos.CodigoParlamentar, CodigoSessaoVotacao, voto_num) |&gt;
  pivot_wider(
    names_from  = CodigoSessaoVotacao,
    values_from = voto_num,
    values_fill = NA
  )

# 3. Calcular proporção de concordância entre pares
ids &lt;- matriz_votos$Votos.CodigoParlamentar
mat &lt;- as.matrix(matriz_votos[, -1])

concordancia &lt;- outer(
  seq_len(nrow(mat)),
  seq_len(nrow(mat)),
  Vectorize(function(i, j) {
    em_comum &lt;- !is.na(mat[i, ]) & !is.na(mat[j, ])
    if (sum(em_comum) &lt; 5) return(NA_real_)
    mean(mat[i, em_comum] == mat[j, em_comum])
  })
)
rownames(concordancia) &lt;- ids
colnames(concordancia) &lt;- ids

# 4. Top 10 pares com maior concordância
as.data.frame(as.table(concordancia)) |&gt;
  setNames(c("senador_a", "senador_b", "concordancia")) |&gt;
  filter(senador_a &lt; senador_b, !is.na(concordancia)) |&gt;
  arrange(desc(concordancia)) |&gt;
  slice_head(n = 10)

8.5 Análise de texto: palavras mais frequentes
Use o pacote tidytext para tokenização robusta. Stopwords em português requerem o pacote stopwords:
# install.packages(c("tidytext", "stopwords"))
library(tidytext)
library(stopwords)
library(dplyr)

# Stopwords em português
sw_pt &lt;- tibble(palavra = stopwords("pt", source = "stopwords-iso"))

# Com extrair_discursos() — coluna TextoResumo
palavras_freq &lt;- discursos |&gt;
  filter(!is.na(TextoResumo)) |&gt;
  unnest_tokens(palavra, TextoResumo) |&gt;
  anti_join(sw_pt, by = "palavra") |&gt;
  filter(nchar(palavra) &gt; 2) |&gt;
  count(palavra, sort = TRUE) |&gt;
  slice_head(n = 20)

# Com extrair_pronunciamentos_multi() — coluna Resumo_Pronunciamento
palavras_freq_multi &lt;- pronunciamentos |&gt;
  filter(!is.na(Resumo_Pronunciamento)) |&gt;
  unnest_tokens(palavra, Resumo_Pronunciamento) |&gt;
  anti_join(sw_pt, by = "palavra") |&gt;
  filter(nchar(palavra) &gt; 2) |&gt;
  count(palavra, sort = TRUE) |&gt;
  slice_head(n = 20)

palavras_freq
#&gt; # A tibble: 20 × 2
#&gt;    palavra              n
#&gt;    &lt;chr&gt;            &lt;int&gt;
#&gt;  1 senhor             312
#&gt;  2 brasil             198
#&gt;  3 governo            187
#&gt;  4 aprovação          143
#&gt;  ...






TipAnálise de sentimentos e tópicos



Para análises mais avançadas de texto, combine senatebR com pacotes de NLP:

tidytext — análise tidy de texto
quanteda — corpus e análise de frequência
stm — modelagem de tópicos estrutural
lexiconPT — léxico de sentimentos em português (disponível no CRAN)

# install.packages("lexiconPT")
library(lexiconPT)

# Carregar léxico de sentimentos em português (OpLexicon v3.0)
data("oplexicon_v3.0")

sentimentos &lt;- pronunciamentos |&gt;
  filter(!is.na(Resumo_Pronunciamento)) |&gt;
  unnest_tokens(palavra, Resumo_Pronunciamento) |&gt;
  inner_join(oplexicon_v3.0, by = c("palavra" = "term")) |&gt;
  group_by(Codigo_Parlamentar) |&gt;
  summarise(polaridade_media = mean(polarity), .groups = "drop")






Note



sentimentBR não está no CRAN. Use lexiconPT como alternativa mantida e disponível para instalação via install.packages("lexiconPT").

